-- Prisma-managed lifecycle fields for Athlete.
--
-- This is intentionally a no-op at the database layer:
-- - `@default(uuid())` is generated by Prisma Client for String IDs.
-- - `@updatedAt` is maintained by Prisma Client on writes.
--
-- Existing PostgreSQL column definitions remain valid:
-- - "Athlete"."id" TEXT NOT NULL PRIMARY KEY
-- - "Athlete"."updatedAt" TIMESTAMP(3) NOT NULL
